async fn send_with_retry(
    &self,
    request: &MessageRequest,
) -> Result<reqwest::Response, ApiError> {
    let mut attempts = 0;
    let mut last_error: Option<ApiError>;

    loop {
        attempts += 1;
        if let Some(session_tracer) = &self.session_tracer {
            session_tracer.record_http_request_started(
                attempts,
                "POST",
                "/v1/messages",
                Map::new(),
            );
        }
        match self.send_raw_request(request).await {
            Ok(response) => match expect_success(response).await {
                Ok(response) => {
                    if let Some(session_tracer) = &self.session_tracer {
                        session_tracer.record_http_request_succeeded(
                            attempts,
                            "POST",
                            "/v1/messages",
                            response.status().as_u16(),
                            request_id_from_headers(response.headers()),
                            Map::new(),
                        );
                    }
                    return Ok(response);
                }
                Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => {
                    self.record_request_failure(attempts, &error);
                    last_error = Some(error);
                }
                Err(error) => {
                    self.record_request_failure(attempts, &error);
                    return Err(error);
                }
            },
            Err(error) if error.is_retryable() && attempts <= self.max_retries + 1 => {
                self.record_request_failure(attempts, &error);
                last_error = Some(error);
            }
            Err(error) => {
                self.record_request_failure(attempts, &error);
                return Err(error);
            }
        }

        if attempts > self.max_retries {
            break;
        }

        tokio::time::sleep(self.backoff_for_attempt(attempts)?).await;
    }

    Err(ApiError::RetriesExhausted {
        attempts,
        last_error: Box::new(last_error.expect("retry loop must capture an error")),
    })
}

async fn send_raw_request(
    &self,
    request: &MessageRequest,
) -> Result<reqwest::Response, ApiError> {
    let request_url = format!("{}/v1/messages", self.base_url.trim_end_matches('/'));
    let request_builder = self
        .http
        .post(&request_url)
        .header("content-type", "application/json");
    let mut request_builder = self.auth.apply(request_builder);
    for (header_name, header_value) in self.request_profile.header_pairs() {
        request_builder = request_builder.header(header_name, header_value);
    }

    let request_body = self.request_profile.render_json_body(request)?;
    if std::env::var("CLAW_LOG_API").is_ok() {
        let mut log_body = request_body.clone();
        if let Some(tools) = log_body.get("tools").and_then(|t| t.as_array()) {
            let names: Vec<String> = tools
                .iter()
                .filter_map(|t| t.get("name").and_then(|n| n.as_str()).map(String::from))
                .collect();
            let summary = serde_json::json!({
                "count": names.len(),
                "names": names,
            });
            if let Some(obj) = log_body.as_object_mut() {
                obj.insert("tools".to_string(), summary);
            }
        }
        eprintln!("\n===== OUTGOING API REQUEST =====");
        eprintln!("POST {request_url}");
        eprintln!(
            "{}",
            serde_json::to_string_pretty(&log_body)
                .unwrap_or_else(|_| "<failed to serialize body>".to_string())
        );
        eprintln!("===== END OUTGOING API REQUEST =====\n");
    }
